function solve(prices: number[], strategy: number[], k: number): number {
    const n = prices.length;
    let originalProfit = 0;
    for (let i = 0; i < n; i++) {
        originalProfit += strategy[i] * prices[i];
    }

    const prefixPrices = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) {
        prefixPrices[i + 1] = prefixPrices[i] + prices[i];
    }

    const prefixStrategy = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) {
        prefixStrategy[i + 1] = prefixStrategy[i] + strategy[i] * prices[i];
    }

    let maxDelta = 0;
    const half = k / 2;

    for (let i = 0; i <= n - k; i++) {
        const sumSecond = prefixPrices[i + k] - prefixPrices[i + half];
        const originalContribution = prefixStrategy[i + k] - prefixStrategy[i];
        const delta = sumSecond - originalContribution;
        if (delta > maxDelta) {
            maxDelta = delta;
        }
    }

    return originalProfit + maxDelta;
}
